-- SQL скрипт для заполнения таблицы brands с нуля
-- Сгенерировано автоматически
-- ВНИМАНИЕ: Этот скрипт очищает таблицу и заполняет её заново!

BEGIN;

-- Очистка таблицы (soft delete всех существующих)
UPDATE brands SET deleted_at = NOW(), updated_at = NOW() WHERE deleted_at IS NULL;

-- Вставка консолидированных брендов

COMMIT;

-- Проверка результатов
SELECT COUNT(*) as total_brands FROM brands WHERE deleted_at IS NULL;
SELECT name, orig_name, aliases FROM brands WHERE deleted_at IS NULL ORDER BY name LIMIT 10;
